import{_ as d,o as e,c as o,a5 as r}from"./chunks/framework.CUCg8a0H.js";const m=JSON.parse('{"title":"v1 边界与路线图","description":"","frontmatter":{"outline":2},"headers":[],"relativePath":"sdk/limits.md","filePath":"sdk/limits.md","lastUpdated":1784005699000}'),s={name:"sdk/limits.md"};function c(a,t,n,l,i,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="v1-边界与路线图" tabindex="-1">v1 边界与路线图 <a class="header-anchor" href="#v1-边界与路线图" aria-label="Permalink to &quot;v1 边界与路线图&quot;">​</a></h1><blockquote><p><strong>读完本页你能</strong>：分清 brainary-agent-sdk v1 明确不做的事、它们各自归到哪个里程碑（llmy 上游 / core），看懂 <strong>接口全表面 × Brainary 决策的覆盖矩阵</strong>，以及「SDK 是门面不是内核」这条裁决背后的理由。</p></blockquote><h2 id="概念简述" tabindex="-1">概念简述 <a class="header-anchor" href="#概念简述" aria-label="Permalink to &quot;概念简述&quot;">​</a></h2><p>brainary-agent-sdk v1 <strong>规划交付（尚未实现）</strong>：一次性 + 多轮入口、统一 <code>Options</code>、轻量自定义工具、进程内 resume、步级流、步边界中断、只读 transcript 导出。</p><p>一批能力 v1 <strong>明确不做</strong>——但要点是：<strong>类型已建齐，仅数据受限</strong>。消息模型的形态（四类消息 × 四种内容块）现在就完整摆好，<code>#[non_exhaustive]</code> 保证后续加法不破坏；v1 只是不去<strong>填充</strong>那些依赖上游的数据。</p><p><strong>状态说明</strong>：brainary-agent-sdk 当前<strong>全部接口均为 🟠【规划中，未完成】</strong>——架构已规划、尚未实现；下方给出的类型、签名、字段均为<strong>已承诺的形态</strong>，供对齐讨论，非占位草案。（⚪ = 暂缓 / 不纳入，非交付接口。）</p><h2 id="v1-明确不做" tabindex="-1">v1 明确不做 <a class="header-anchor" href="#v1-明确不做" aria-label="Permalink to &quot;v1 明确不做&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>状态</th><th>归属</th><th>说明</th></tr></thead><tbody><tr><td>token 级流式输出</td><td>🟠</td><td>llmy 上游</td><td>现为<strong>步级</strong>流：每完成一步产出一条 <code>Message</code>；token 级待上游</td></tr><tr><td>跨进程 resume（从 transcript 续跑）</td><td>🟠</td><td>llmy 上游</td><td>llmy 无「从历史重建 agent」的构造器；进程内 resume 规划由 <code>BrainaryClient</code> 支持</td></tr><tr><td>步内中断</td><td>🟠</td><td>llmy 上游</td><td>现为<strong>步边界</strong>协作式中断；llmy 无步内取消</td></tr><tr><td>真实 cost 计量</td><td>🟠</td><td>llmy 上游</td><td><code>ResultMessage.usage</code> / <code>total_cost_usd</code> 恒 <code>None</code>，类型已就位（见 <a href="/docs/43b8395/sdk/messages.html#cost">消息模型</a>）</td></tr><tr><td>结构化 <code>tool_use</code> / <code>tool_result</code> 块填充</td><td>🟠</td><td>llmy 上游</td><td><code>ContentBlock::ToolUse/ToolResult/Thinking</code> 类型已建齐，<strong>v1 不填充</strong>；工具调用现只给 <code>AssistantMessage.requested_tools</code> 粗信号</td></tr><tr><td>自动压缩（<code>Options.auto_compact</code>）</td><td>🟠</td><td>core</td><td>旋钮就位，v1 仅 <code>AutoCompact::Off</code> 有意义</td></tr><tr><td>手动 <code>compact()</code></td><td>⚪</td><td>不暴露</td><td><strong>故意</strong>不给（footgun，见下）</td></tr></tbody></table><p><code>Message</code> 各字段的逐项填充度对照表见 <a href="/docs/43b8395/sdk/messages.html">消息模型</a>。</p><h2 id="待-llmy-上游-原-m5" tabindex="-1">待 llmy 上游（原 M5） <a class="header-anchor" href="#待-llmy-上游-原-m5" aria-label="Permalink to &quot;待 llmy 上游（原 M5）&quot;">​</a></h2><p>以下都卡在 llmy 上游能力，llmy 补齐后 SDK 加法式填入，无破坏：</p><ul><li><strong>token 级流</strong>：把步级流细化到 token。</li><li><strong>跨进程真 resume</strong>：从导出的 transcript 载入新进程继续跑。</li><li><strong>步内中断</strong>：不必等当前步跑完即可取消。</li><li><strong>真实 cost</strong>：填充 <code>ResultMessage.usage</code> 与 <code>total_cost_usd</code>。</li><li><strong>结构化 <code>tool_use</code> / <code>tool_result</code> 填充</strong>：把工具调用/结果作为结构化 <code>ContentBlock</code> 真正填充出来，取代当前的 <code>requested_tools</code> 粗信号。</li></ul><h2 id="待-core-原-m6" tabindex="-1">待 core（原 M6） <a class="header-anchor" href="#待-core-原-m6" aria-label="Permalink to &quot;待 core（原 M6）&quot;">​</a></h2><ul><li><strong>自动压缩策略</strong>：上下文治理的自动压缩由 <strong>core 拥有</strong>并实现；<code>Options.auto_compact</code> 旋钮规划就位，落地后翻开 <code>Auto</code> / <code>Threshold(_)</code> 即可用。</li><li>在此之前，v1 的上下文治理靠<strong>溢出护栏</strong>兜底（逼近窗口以 <code>StopReason::ContextExhausted</code> 明确停），见 <a href="/docs/43b8395/sdk/interrupt-and-guardrails.html">中断、护栏与上下文</a>。</li></ul><h2 id="裁决理由" tabindex="-1">裁决理由 <a class="header-anchor" href="#裁决理由" aria-label="Permalink to &quot;裁决理由&quot;">​</a></h2><ul><li><strong>SDK 是门面，不是内核</strong>。凡触及核心语义（compaction、上下文治理）的决策权在 <strong>core</strong>，不在门面 SDK。因此自动压缩策略归 M6/core，SDK 只暴露旋钮。</li><li><strong>手动 <code>compact()</code> 故意不暴露</strong>：手动压缩是 footgun——会让上下文治理的责任在门面与内核之间割裂。上下文治理统一走「core 拥有的自动压缩策略（M6）＋ v1 的溢出护栏」，而不是把一个易误用的手动钮塞给调用方。</li><li><strong>类型先行</strong>：把消息模型、<code>usage</code>、结构化块等类型现在就建齐并标 <code>#[non_exhaustive]</code>，是为了 M5/M6 能纯加法式填数据，调用方代码不必因为版本升级而改。</li></ul><h2 id="coverage-matrix" tabindex="-1">覆盖矩阵：接口全表面与决策 <a class="header-anchor" href="#coverage-matrix" aria-label="Permalink to &quot;覆盖矩阵：接口全表面与决策 {#coverage-matrix}&quot;">​</a></h2><p>这张表把 agent SDK 的<strong>全部</strong>公开接口过一遍，<strong>站在「Brainary-Code-like agent SDK」这一目标工具的位置</strong>逐行裁决，每行给出 Brainary 的处置决策与一句理由。它是本站<strong>权威</strong>的「扫过完整表面 × 我方决策」总表：凡判 ⚪（暂缓/仅登记）的都给出明确理由（多为 CLI 子进程内部管线、已退役接口或工具宇宙不同者），而非把边缘接口一概推迟——传输、流事件、限流、后台任务消息、<strong>命令沙箱</strong>、插件、Hooks、内置工具目录、设置来源等面均从目标工具视角逐项重判并登记在下。</p><p><strong>决策标签</strong>：🟠 纳入本站交付面（【规划中，未完成】——架构已规划、尚未实现） · ⬇️ 下沉核心层（非本站门面职责） · ⚪ 暂缓 / 不纳入（仅登记，附理由）。凡「纳入」的接口当前一律为 🟠，不再细分实现档位。</p><h3 id="入口与函数" tabindex="-1">入口与函数 <a class="header-anchor" href="#入口与函数" aria-label="Permalink to &quot;入口与函数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>接口</th><th>决策</th><th>一句理由 / 去处</th></tr></thead><tbody><tr><td><code>query()</code></td><td>🟠</td><td>一次性入口 = 会议的 QE，<a href="/docs/43b8395/sdk/query-and-client.html">两个入口</a></td></tr><tr><td><code>BrainaryClient</code></td><td>🟠</td><td>有状态多轮 = 会议的 client，<a href="/docs/43b8395/sdk/query-and-client.html">两个入口</a></td></tr><tr><td><code>#[tool]</code>（宏）</td><td>🟠</td><td><code>#[tool]</code> 宏，<a href="/docs/43b8395/sdk/tools.html">自定义工具</a></td></tr><tr><td><code>FunctionTools</code>（命名能力单元）</td><td>🟠</td><td><code>FunctionTools</code>（命名能力单元），<a href="/docs/43b8395/sdk/tools.html">自定义工具</a></td></tr><tr><td><code>list_sessions</code> / <code>get_session_messages</code> / <code>get_session_info</code> / <code>rename_session</code></td><td>🟠</td><td>架构要、实现待跨进程持久化底座，<a href="/docs/43b8395/sdk/sessions.html">会话管理</a></td></tr><tr><td><code>tag_session</code></td><td>⚪</td><td>可选，登记待议</td></tr></tbody></table><h3 id="类型" tabindex="-1">类型 <a class="header-anchor" href="#类型" aria-label="Permalink to &quot;类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>接口</th><th>决策</th><th>一句理由 / 去处</th></tr></thead><tbody><tr><td><code>Options</code></td><td>🟠</td><td><code>Options</code> builder，<a href="/docs/43b8395/sdk/options.html">Options</a></td></tr><tr><td><code>SystemPrompt</code></td><td>🟠</td><td><code>SystemPrompt</code> 枚举（Default/Inline/TemplateFile），<a href="/docs/43b8395/sdk/options.html#系统提示-systemprompt">Options</a></td></tr><tr><td><code>Message</code> / <code>ContentBlock</code> 及各变体</td><td>🟠</td><td>各变体一一就位，<a href="/docs/43b8395/sdk/messages.html">消息模型</a></td></tr><tr><td><code>billing_cap</code> / <code>ResultMessage.total_cost_usd</code></td><td>🟠</td><td>成本面：<code>billing_cap</code> 规划就位、<code>total_cost_usd</code> 恒 <code>None</code> 待上游，<a href="/docs/43b8395/sdk/messages.html#cost">成本</a></td></tr><tr><td><code>usage</code>（token 计量）</td><td>🟠</td><td>类型就位、恒 <code>None</code> 待上游</td></tr><tr><td><code>PermissionMode</code> / <code>CanUseTool</code> / <code>PermissionResult</code></td><td>🟠</td><td>控制面表面三件套，占位，<a href="/docs/43b8395/sdk/permissions.html">权限模型</a>（已从占位改写为完整规范）</td></tr><tr><td><code>ToolPermissionContext</code></td><td>🟠</td><td><code>CanUseTool</code> 回调自身的入参，属控制面 CORE，占位，<a href="/docs/43b8395/sdk/permissions.html">权限模型</a></td></tr><tr><td><code>PermissionUpdate</code> / <code>PermissionRuleValue</code></td><td>🟠</td><td>运行期改规则并持久化的<strong>公开</strong>机制（非 CLI 内部），占位，<a href="/docs/43b8395/sdk/permissions.html">权限模型</a></td></tr><tr><td><code>AgentDefinition</code>（子 agent）</td><td>🟠</td><td>提升为 SDK 表面 <code>Options.agents</code>：程序化子 agent 是本工具头等特性；深度装配仍可交叉引用 核心层</td></tr><tr><td><code>ToolAnnotations</code></td><td>🟠</td><td>工具行为提示，供权限层用，占位，<a href="/docs/43b8395/sdk/tools.html#toolannotations-工具行为提示-架构占位">自定义工具</a></td></tr><tr><td><code>McpServerConfig</code> 家族（Stdio/SSE/Http）</td><td>🟠</td><td><code>mcp_server()</code> 糖目前只收 URL；需补 stdio <code>args</code>/<code>env</code> 与<strong>鉴权 <code>headers</code></strong>（缺 headers 无法配置需鉴权的远程 MCP），MCP</td></tr><tr><td><code>BrainaryError</code>（语义错误模型）</td><td>🟠</td><td><code>BrainaryError</code> 枚举（构建期领域变体 🟠）+ <code>ErrorCategory</code> 可恢复性分类（🟠），<a href="/docs/43b8395/sdk/errors.html">错误处理</a></td></tr><tr><td><code>CLINotFoundError</code> / <code>CLIConnectionError</code> / <code>ProcessError</code> / <code>CLIJSONDecodeError</code> 一族</td><td>⚪</td><td>这些是 CLI 子进程传输方式的副作用（缺二进制/连不上/非零退出/JSON 解析失败）；brainary-agent-sdk 是<strong>进程内库</strong>，无子进程/二进制/JSON 管线，故不纳入（OUT），<a href="/docs/43b8395/sdk/errors.html#cli-error-family-out">错误处理</a></td></tr><tr><td>Hook types</td><td>🟠</td><td>确定性治理层，整只子系统已成规范，占位，<a href="/docs/43b8395/sdk/hooks.html">Hooks</a></td></tr><tr><td><code>OutputFormat</code> / <code>ThinkingConfig</code> / <code>EffortLevel</code></td><td>🟠</td><td>结构化输出对库调用尤其有用；thinking/effort 是现代 agent 控制面，多归 <code>llm_settings</code>，占位</td></tr><tr><td><code>SettingSource</code> / setting_sources</td><td>🟠</td><td>是否加载 user/project/local 设置（含项目内存文件）；传空 = hermetic，利于 CI，占位</td></tr><tr><td><code>ToolsPreset</code></td><td>⚪</td><td>该预设的工具宇宙与 Brainary 不同，不移植（OUT）</td></tr><tr><td><code>SdkBeta</code></td><td>⚪</td><td>已退役，仅登记（OUT）</td></tr><tr><td><code>Transport</code>（自定义传输）</td><td>⚪</td><td>CLI 子进程逃生口；Brainary 内部自持传输，不作公共旋钮</td></tr><tr><td><code>StreamEvent</code>（partial 消息）</td><td>🟠</td><td>归 token 级流式——现为步级，类型面待上游</td></tr><tr><td><code>RateLimitEvent</code> / <code>RateLimitInfo</code></td><td>🟠</td><td>面向托管模型的 agent SDK 应暴露限流状态以便退避，占位</td></tr><tr><td>后台任务消息（<code>TaskStarted</code> / <code>TaskProgress</code> / <code>TaskNotification</code> + <code>TaskUsage</code>）</td><td>🟠</td><td>随 <code>stop_task</code>；v1 无后台任务模型</td></tr><tr><td><code>SandboxSettings</code> 家族</td><td>🟠</td><td>宿主内<strong>命令沙箱</strong>：约束 bash 工具的文件/命令/网络，占位。与 PoA/wasm 隔离整只 <code>.poa</code> 是不同概念，两者都要</td></tr><tr><td><code>SdkPluginConfig</code> / plugins</td><td>🟠</td><td>SDK <strong>程序化</strong>加载本地插件包（commands/agents/mcp），占位</td></tr></tbody></table><h3 id="内置工具与授权" tabindex="-1">内置工具与授权 <a class="header-anchor" href="#内置工具与授权" aria-label="Permalink to &quot;内置工具与授权&quot;">​</a></h3><table tabindex="0"><thead><tr><th>接口</th><th>决策</th><th>一句理由 / 去处</th></tr></thead><tbody><tr><td><strong>内置工具目录</strong>（Read/Write/Edit/Bash/Glob/Grep/WebFetch/WebSearch/Agent 等，Brainary 原生名）</td><td>🟠</td><td>编码智能体 SDK 的定义性面：文件类规划由 <code>FolderPrimitive</code> 装配（schema 待精化），shell/web/交互/任务/子 agent 均规划中，<a href="/docs/43b8395/sdk/builtin-tools.html">内置工具目录</a></td></tr><tr><td><code>allowed_tools</code> / <code>disallowed_tools</code></td><td>🟠</td><td>声明式授权清单（可用性 ≠ 授权），占位，<a href="/docs/43b8395/sdk/permissions.html">权限模型</a></td></tr><tr><td><code>permission_mode</code>（6 模）/ <code>CanUseTool</code> / <code>PermissionResult</code></td><td>🟠</td><td>控制面三件套，占位，指向已改写为完整规范的 <a href="/docs/43b8395/sdk/permissions.html">权限模型</a></td></tr></tbody></table><h3 id="运行时控制-客户端方法" tabindex="-1">运行时控制（客户端方法） <a class="header-anchor" href="#运行时控制-客户端方法" aria-label="Permalink to &quot;运行时控制（客户端方法）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>接口</th><th>决策</th><th>一句理由 / 去处</th></tr></thead><tbody><tr><td><code>connect</code> / <code>query</code> / <code>interrupt</code> / <code>disconnect</code></td><td>🟠</td><td>规划中，<a href="/docs/43b8395/sdk/query-and-client.html#full-method-face">两个入口</a></td></tr><tr><td><code>set_model</code> / <code>set_permission_mode</code> / <code>rewind_files</code></td><td>🟠</td><td>运行时切换/文件检查点未做</td></tr><tr><td><code>get_mcp_status</code> / <code>reconnect_mcp_server</code> / <code>toggle_mcp_server</code></td><td>🟠</td><td>MCP 运行时控制未做，v1 仅装配期挂载</td></tr><tr><td><code>stop_task</code></td><td>🟠</td><td>无后台任务模型</td></tr><tr><td><code>get_server_info</code></td><td>🟠</td><td>部分由 <code>system_prompt()</code> / <code>context_window()</code> getter 覆盖</td></tr></tbody></table><blockquote><p><strong>Brainary 独有</strong>：<code>step_once</code> / <code>revert</code>（手动单步回退）、<code>export_transcript</code>（只读快照）、<code>approx_context_tokens</code> / <code>context_window</code>（上下文检视）——均为 🟠【规划中，未完成】，见 <a href="/docs/43b8395/sdk/query-and-client.html#brainaryclient-透传方法">两个入口</a>。</p></blockquote><h2 id="相关" tabindex="-1">相关 <a class="header-anchor" href="#相关" aria-label="Permalink to &quot;相关&quot;">​</a></h2><ul><li><a href="/docs/43b8395/sdk/messages.html">消息模型</a> —— 逐字段 v1 填充度对照表 · <a href="/docs/43b8395/sdk/messages.html#cost">成本字段</a></li><li><a href="/docs/43b8395/sdk/sessions.html">会话管理</a> · <a href="/docs/43b8395/sdk/permissions.html">权限模型</a> · <a href="/docs/43b8395/sdk/errors.html">错误处理</a> —— 三个占位/新增面</li><li><a href="/docs/43b8395/sdk/interrupt-and-guardrails.html">中断、护栏与上下文</a> —— 步边界中断、<code>max_turns</code>、溢出护栏、<code>auto_compact</code> 占位</li><li><a href="/docs/43b8395/sdk/transcript.html">会话导出</a> —— 只导出、不可续跑（跨进程 resume 待上游）</li></ul>',30)])])}const u=d(s,[["render",c]]);export{m as __pageData,u as default};
